interface Member {
  id: number;
  memberCode: string;
  firstName: string;
  lastName: string;
  fullName: string;
  username?: string;
  password?: string;
  phone: string;
  email: string;
  dob: string;
  gender: string;
  address: string;
  status: string;
  registrationDate?: string;
  expiryDate: string;
  package: string;
  createdBy?: string;
  revenue?: number;
  avatar?: string;
  faceData?: string;
  discount: number;
  paymentMethod: string;
}

interface KPI {
  username: string;
  fullName: string;
  role: string;
  count: number;
  revenue: number;
}

interface Package {
  id: number;
  name: string;
  duration: string;
  price: number;
  description: string;
  status: string;
}

interface Stats {
  totalMembers: number;
  activeMembers: number;
  expiredMembers: number;
  checkinsToday: number;
  revenueThisMonth: number;
  infrastructure?: {
    apiStatus: string;
    mobileSync: string;
    lastSync: string;
  };
}

interface MobileProfile {
  id: number;
  fullName: string;
  package: string;
  expiryDate: string;
  status: string;
  qrCode: string;
}

interface Checkin {
  id: number;
  memberId: number;
  memberName: string;
  time: string;
}

interface User {
  id: number;
  username: string;
  role: "ADMIN" | "STAFF" | "PT" | "MEMBER" | "RECEPTIONIST";
  fullName: string;
  avatar?: string;
  email?: string;
}

interface Notification {
  id: string;
  type: "success" | "error" | "info";
  message: string;
}

interface PT {
  id: number;
  fullName: string;
  expertise: string[];
  level: "Junior" | "Senior" | "Master";
  commissionRate: number;
  isActive: boolean;
  phone: string;
  email: string;
  username?: string;
  password?: string;
  avatar?: string;
}

interface PTAssignment {
  id: number;
  memberId: number;
  trainerId: number;
  totalSessions: number;
  sessionsLeft: number;
  price: number;
  startDate: string;
  expiryDate: string;
  assignedDate?: string;
  status: "Active" | "Completed" | "Expired";
}

interface TrainingSession {
  id: number;
  assignmentId: number;
  date: string;
  notes: string;
  memberId: number;
  trainerId: number;
}

interface PTStat {
  trainerId: number;
  fullName: string;
  totalRevenue: number;
  commission: number;
  sessionsTotal: number;
  activeClients: number;
}

interface Product {
  id: number;
  name: string;
  category: string;
  price: number;
  stock: number;
  image?: string;
}

interface Transaction {
  id: number;
  type: "INCOME" | "EXPENSE";
  amount: number;
  category: string;
  note: string;
  date: string;
  createdBy: string;
  customerName?: string;
}

interface CartItem {
  product: Product;
  quantity: number;
}

interface MemberSale {
  id: number;
  customerName: string;
  serviceName: string;
  dateTime: string;
  total: number;
  discount: number;
  paymentMethod: string;
  paidAmount: number;
  status: "Hoàn thành";
  startDate?: string;
  expiryDate?: string;
}

interface EvaluationReply {
  id: number;
  senderName: string;
  senderRole: "MEMBER" | "STAFF" | "ADMIN" | "PT";
  text: string;
  date: string;
}

interface Evaluation {
  id: number;
  memberId: number;
  memberName: string;
  rating: number;
  comment: string;
  date: string;
  replies?: EvaluationReply[];
}

interface StaffMember {
  id: number;
  fullName: string;
  role: "ADMIN" | "STAFF" | "PT" | "RECEPTIONIST";
  position: string;
  baseSalary: number;
  hourlyRate: number;
  phoneNumber: string;
  email: string;
  username?: string;
  password?: string;
  isActive: boolean;
  status?: string;
  shiftHours: { start: string; end: string };
}

interface AttendanceLog {
  id: number;
  staffId: number;
  checkIn: string;
  checkOut: string | null;
  totalHours: number;
  date: string;
  isOT: boolean;
}

interface PayrollRecord {
  id: number;
  staffId: number;
  month: string;
  basePay: number;
  commission: number;
  ptBonus: number;
  otPay: number;
  totalPay: number;
  status: "Draft" | "Paid";
}

interface Equipment {
  id: number;
  name: string;
  code: string;
  category: string;
  status: "NORMAL" | "MAINTENANCE_REQUIRED" | "BROKEN" | "UNDER_MAINTENANCE";
  purchaseDate: string;
  lastMaintenance: string;
  nextMaintenance: string;
  location: string;
  history: { date: string; action: string; note: string }[];
}

interface MaintenanceTask {
  id: number;
  equipmentId: number;
  equipmentName: string;
  scheduledDate: string;
  taskType: "ROUTINE" | "REPAIR";
  priority: "LOW" | "MEDIUM" | "HIGH";
  performer: string;
  status: "PENDING" | "IN_PROGRESS" | "COMPLETED";
  notes: string;
}

interface FacilityIncident {
  id: number;
  equipmentId?: number;
  equipmentName: string;
  location: string;
  reporter: string;
  description: string;
  reportedDate: string;
  severity: "LOW" | "MEDIUM" | "HIGH";
  status: "NEW" | "IN_PROGRESS" | "RESOLVED";
  resolutionNotes?: string;
}

interface ConfirmDialog {
  isOpen: boolean;
  title: string;
  message: string;
  onConfirm: () => void;
  type?: "danger" | "info";
}

