  const getPasswordStrength = (pass: string) => {
    if (!pass) return { score: 0, label: "Empty", labelVi: "Trống", color: "bg-zinc-805 text-zinc-500", barColor: "bg-zinc-800" };
    let score = 0;
    if (pass.length >= 6) score += 1;
    if (pass.length >= 8) score += 1;
    if (/[0-9]/.test(pass)) score += 1;
    if (/[A-Z]/.test(pass)) score += 1;
    if (/[^a-zA-Z0-9]/.test(pass)) score += 1;

    if (score <= 1) return { score, label: "Very Weak", labelVi: "Rất yếu", color: "text-red-500 bg-red-500/10 border border-red-500/20", barColor: "bg-red-500 w-1/4" };
    if (score === 2) return { score, label: "Weak", labelVi: "Yếu", color: "text-orange-500 bg-orange-500/10 border border-orange-500/20", barColor: "bg-orange-500 w-2/4" };
    if (score === 3) return { score, label: "Medium", labelVi: "Trung bình", color: "text-yellow-500 bg-yellow-500/10 border border-yellow-500/20", barColor: "bg-yellow-500 w-3/4" };
    return { score, label: "Strong", labelVi: "Mạnh", color: "text-emerald-500 bg-emerald-500/10 border border-emerald-500/20", barColor: "bg-emerald-400 w-full" };
  };

