  const translateCategoryName = (cat: string) => {
    if (!cat) return "";
    const trimmed = cat.trim();
    
    // Exact match for default system categories
    const matches: Record<string, Record<string, string>> = {
      "Bán lẻ": {
        "vi": "Bán lẻ",
        "en": "Retail / POS Sale",
        "zh": "商品零售"
      },
      "Gia hạn gói tập": {
        "vi": "Gia hạn gói tập",
        "en": "Membership Renewal",
        "zh": "会员续费"
      },
      "Phí gói tập": {
        "vi": "Phí gói tập",
        "en": "Membership Registration",
        "zh": "购卡会籍费"
      },
      "Hội viên mới": {
        "vi": "Hội viên mới",
        "en": "New Registration",
        "zh": "新购买会籍"
      }
    };
    
    if (matches[trimmed]) {
      return matches[trimmed][lang] || trimmed;
    }
    
    // Fallback translations for custom categories
    if (lang === "en") {
      if (trimmed.toLowerCase().includes("mặt bằng")) return "Rent / Facilities";
      if (trimmed.toLowerCase().includes("điện nước")) return "Utilities";
      if (trimmed.toLowerCase().includes("lương")) return "Staff Salaries";
      if (trimmed.toLowerCase().includes("thiết bị")) return "Gym Equipments";
      if (trimmed.toLowerCase().includes("phụ kiện")) return "Supplements & Gear";
      if (trimmed.toLowerCase().includes("khác")) return "Others";
    } else if (lang === "zh") {
      if (trimmed.toLowerCase().includes("mặt bằng")) return "场地租金";
      if (trimmed.toLowerCase().includes("điện nước")) return "水费电费";
      if (trimmed.toLowerCase().includes("lương")) return "员工薪资";
      if (trimmed.toLowerCase().includes("thiết bị")) return "器械设备";
      if (trimmed.toLowerCase().includes("phụ kiện")) return "营养品装备";
      if (trimmed.toLowerCase().includes("khác")) return "其他";
    }
    
    return trimmed;
  };

  const translateCustomerName = (name: string) => {
    if (!name) return "-";
    const trimmed = name.trim();
    if (trimmed === "Khách lẻ") {
      return lang === 'vi' ? 'Khách lẻ' : (lang === 'zh' ? '散客 / 零售客户' : 'Walk-in Guest');
    }
    return name;
  };

  const translateTxNote = (note: string) => {
    if (!note) return "";
    
    // 1. Bán Whey Protein
    if (note.includes("Bán Whey Protein")) {
      const map: Record<string, string> = {
        vi: "Bán Whey Protein",
        en: "Retail Whey Protein Sale",
        zh: "零售销售乳清蛋白粉"
      };
      return map[lang] || map["vi"];
    }

    // 2. Thanh toán đơn hàng POS (X mặt hàng)
    const posMatch = note.match(/Thanh toán đơn hàng POS \((\d+)\s+mặt hàng\)/i);
    if (posMatch) {
      const qty = posMatch[1];
      if (lang === "en") {
        return `POS order checkout (${qty} items)`;
      } else if (lang === "zh") {
        return `POS 结算订单 (${qty} 件商品)`;
      }
      return `Thanh toán đơn hàng POS (${qty} mặt hàng)`;
    }

    // 3. Mua sản phẩm tại quầy POS
    if (note.includes("Mua sản phẩm tại quầy POS")) {
      const map: Record<string, string> = {
        vi: "Mua sản phẩm tại quầy POS",
        en: "Purchase items at POS counter",
        zh: "在POS柜台购买商品"
      };
      return map[lang] || map["vi"];
    }

    // 4. Gia hạn: [NAME] - [PACKAGE]
    const renewMatch = note.match(/Gia hạn:\s*(.+?)\s*-\s*(.+)/i);
    if (renewMatch) {
      const mName = renewMatch[1];
      const pName = translatePackageName(renewMatch[2]);
      if (lang === "en") {
        return `Renew: ${mName} - ${pName}`;
      } else if (lang === "zh") {
        return `续期: ${mName} - ${pName}`;
      }
      return `Gia hạn: ${mName} - ${translatePackageName(renewMatch[2])}`;
    }

    // 5. Hội viên mới: [NAME] - [PACKAGE]
    const newMemberMatch = note.match(/Hội viên mới:\s*(.+?)\s*-\s*(.+)/i);
    if (newMemberMatch) {
      const mName = newMemberMatch[1];
      const pName = translatePackageName(newMemberMatch[2]);
      if (lang === "en") {
        return `New Member: ${mName} - ${pName}`;
      } else if (lang === "zh") {
        return `新会员: ${mName} - ${pName}`;
      }
      return `Hội viên mới: ${mName} - ${translatePackageName(newMemberMatch[2])}`;
    }

    // 6. Utility Bill - Electricity
    const elecMatch = note.match(/Thanh toán điện tháng\s*(\d+)/i);
    if (elecMatch) {
      const month = elecMatch[1];
      if (lang === "en") {
        return `Electricity bill payment for Month ${month}`;
      } else if (lang === "zh") {
        return `支付 ${month} 月电费`;
      }
      return `Thanh toán điện tháng ${month}`;
    }

    // 7. Utility Bill - Water
    const waterMatch = note.match(/Thanh toán nước tháng\s*(\d+)/i);
    if (waterMatch) {
      const month = waterMatch[1];
      if (lang === "en") {
        return `Water bill payment for Month ${month}`;
      } else if (lang === "zh") {
        return `支付 ${month} 月水费`;
      }
      return `Thanh toán nước tháng ${month}`;
    }

    // 8. POS Retail inventory sales issues
    const posIssueMatch = note.match(/Xuất kho bán hàng lẻ POS \(Hóa đơn khách hàng:\s*(.+?)\)/i);
    if (posIssueMatch) {
      const cust = posIssueMatch[1];
      const translatedCust = cust === "Khách lẻ"
        ? (lang === "en" ? "Walk-in Guest" : lang === "zh" ? "散客零售" : "Khách lẻ")
        : cust;
      if (lang === "en") {
        return `POS retail sales inventory outbound (Client: ${translatedCust})`;
      } else if (lang === "zh") {
        return `零售出库：POS 结单 (客户: ${translatedCust})`;
      }
      return `Xuất kho bán hàng lẻ POS (Hóa đơn khách hàng: ${translatedCust})`;
    }

    // 9. Warehouse adjustments
    if (note.includes("Điều chỉnh kho")) {
      if (lang === "en") {
        return note.replace("Điều chỉnh kho", "Inventory Adjustment").replace("theo phiếu", "via form");
      } else if (lang === "zh") {
        return note.replace("Điều chỉnh kho", "库量变动调整").replace("theo phiếu", "单号");
      }
    }

    // 10. Purchase orders & imports
    if (note.includes("Kho hàng nhập khẩu trực tiếp theo PO")) {
      if (lang === "en") {
        return note.replace("Kho hàng nhập khẩu trực tiếp theo PO", "Warehouse direct import via PO");
      } else if (lang === "zh") {
        return note.replace("Kho hàng nhập khẩu trực tiếp theo PO", "依采购单 PO 直入商品库");
      }
    }
    if (note.includes("Nhập kho từ đơn đặt hàng đã duyệt")) {
      if (lang === "en") {
        return note.replace("Nhập kho từ đơn đặt hàng đã duyệt", "Restock from approved purchase order");
      } else if (lang === "zh") {
        return note.replace("Nhập kho từ đơn đặt hàng đã duyệt", "根据已审核采购单执行收货入库");
      }
    }

    // fallback mapping translations
    const matches: Record<string, Record<string, string>> = {
      "THANH TOÁN ĐIỆN THÁNG 4": {
        vi: "Thanh toán điện tháng 4",
        en: "Electricity bill payment for Month 4",
        zh: "支付 4 月份电费"
      },
      "THANH TOÁN ĐIỆN THÁNG 5": {
        vi: "Thanh toán điện tháng 5",
        en: "Electricity bill payment for Month 5",
        zh: "支付 5 月份电费"
      }
    };

    const upper = note.toUpperCase().trim();
    if (matches[upper]) {
      return matches[upper][lang] || note;
    }

    return note;
  };

